    "grammar": [
      {
        "formula": "LE / LA / LES + verbe → Je le prends. / Je la prends. / Je les prends.",
        "use": "Pronombre COD que reemplaza la prenda ya conocida. LE = masc. sing., LA = fem. sing., LES = plural. Va SIEMPRE antes del verbo, nunca «je prends le»."
      },
      {
        "formula": "NE + LE/LA/LES + verbe + PAS → Je ne la prends pas.",
        "use": "En negación el pronombre COD va entre NE y el verbo: « Cette robe est trop chère, je ne la prends pas. »"
      },
      {
        "formula": "ÇA + ME + VA (verbe ALLER) → Ça me va très bien.",
        "use": "La frase del probador: usa ALLER, no ÊTRE. Ça me va (me queda bien) · Ça ne me va pas (no me queda). Nunca « c'est me va »."
      },
      {
        "formula": "CE / CET / CETTE / CES + nom → Ce pull, cet imperméable, cette robe, ces chaussures",
        "use": "Demostrativo que SEÑALA la prenda. ce (masc.), cet (masc. con vocal), cette (fem.), ces (plural). El demostrativo señala, el pronombre COD reemplaza."
      }
    ],
